import re

# Function to check if a project started in 2022 based on project text
def project_started_in_2022(project_text):
    """Check if project has 2022 start date in its description"""
    if not project_text:
        return False

    text_lower = project_text.lower()

    # Look for 2022 in schedule/updates
    if '2022' in text_lower:
        # Check if it's related to start/advertising/bidding (which indicates the project is starting)
        start_indicators = [
            'advertise', 'bid', 'begin construction', 
            'construction began', 'project schedule', 'updates',
            'on september', 'on october', 'on november', 'on december'
        ]

        for indicator in start_indicators:
            if indicator in text_lower and '2022' in text_lower:
                # Also make sure it's related to disaster recovery
                if any(word in text_lower for word in ['fema', 'caloes', 'caljpia', 'disaster']):
                    return True

    return False

# Extract project sections from text
def extract_project_sections(text):
    """Extract project sections based on disaster indicators and project structure"""
    projects = []
    lines = text.split('\n')

    disaster_keywords = ['fema', 'caloes', 'caljpia']

    for i, line in enumerate(lines):
        line = line.strip()

        # Skip empty lines and obvious non-project lines
        if not line or line.startswith('Page') or line.startswith('Agenda') or line.startswith('cid'):
            continue

        # Check if line is a project name (length and pattern)
        if len(line) > 10 and any(char.isupper() for char in line[:5]):

            # Check if this is a disaster-related project
            line_lower = line.lower()

            if any(keyword in line_lower for keyword in disaster_keywords):
                # Look ahead to collect project details
                details = []
                for j in range(i+1, min(i+30, len(lines))):
                    next_line = lines[j].strip()

                    # Stop if we hit another project-like line
                    if next_line and len(next_line) > 10 and any(char.isupper() for char in next_line.split()[:3] if next_line.split()):
                        if j - i > 5:  # Only stop if we've collected enough lines
                            break

                    if next_line and not next_line.startswith('Page'):
                        details.append(next_line)

                # Check if project started in 2022
                full_text = line + ' ' + ' '.join(details)
                if project_started_in_2022(full_text):
                    projects.append({
                        'name': line,
                        'text': full_text
                    })

    return projects

print("Script ready to process documents")"}

